function (doc) {
  if (doc.type === "content" && doc.fts) {
    for (var i = 0; i < doc.fts.length; i++) {
      var e = doc.fts[i];
      var c = e.indexOf(":", 3);
      emit(e.substring(0, c), [
        parseFloat(e.substring(c + 1)),
        doc.parentType,
        doc.status,
        doc.publishDate || null,
        doc.expiryDate || null,
        doc.language,
        doc.memberOf,
        doc.parentTags || [],
        doc.updatedTimeUtc || null,
        doc.title || null,
        doc.author || null
      ]);
    }
  }
}
